Scripts.OnClick:
if self:GetID() == 6 and self:GetParent() == CollectionsJournal then
	HideUIPanel(CollectionsJournal);
	local config = ezCollections.Config.Windows[self:GetParent():GetName()];
	if not config.Layout and not config.Lock then
		WardrobeFrame:ClearAllPoints();
		WardrobeFrame:SetPoint("BOTTOMLEFT", UIParent, "BOTTOMLEFT", CollectionsJournal:GetLeft(), CollectionsJournal:GetBottom());
	end
	CollectionsJournal_SetTab(WardrobeFrame, self:GetID());
	ShowUIPanel(WardrobeFrame);
	ezCollections:SetCVarBitfield("closedInfoFrames", LE_FRAME_TUTORIAL_EZCOLLECTIONS_TRANSMOG_TAB, true);
	return;
elseif self:GetID() ~= 6 and self:GetParent() == WardrobeFrame then
	HideUIPanel(WardrobeFrame);
	local config = ezCollections.Config.Windows[self:GetParent():GetName()];
	if not config.Layout and not config.Lock then
		CollectionsJournal:ClearAllPoints();
		CollectionsJournal:SetPoint("BOTTOMLEFT", UIParent, "BOTTOMLEFT", WardrobeFrame:GetLeft(), WardrobeFrame:GetBottom());
	end
	ShowUIPanel(CollectionsJournal);
	CollectionsJournal_SetTab(CollectionsJournal, self:GetID());
	return;
end
CollectionsJournal_SetTab(self:GetParent(), self:GetID());
PlaySound("igCharacterInfoTab");

Scripts.OnLoad:
self:SetFrameLevel(self:GetFrameLevel() + 4);
local textures =
{
	_G[self:GetName().."LeftDisabled"],
	_G[self:GetName().."MiddleDisabled"],
	_G[self:GetName().."RightDisabled"],
};
for i, texture in ipairs(textures) do
	texture:SetTexture([[Interface\AddOns\ezCollections\Textures\UI-Character-ActiveTabCutoff]]);
end

Mixin(self, SetShownMixin);
function self:UpdateVisibility()
	local tab = ezCollections:GetCVar("petJournalTab");
	self:SetShown(ezCollections.Config.Wardrobe.PortraitButton and (tab == 5 or tab == 6));
end

Scripts.OnClick:
HideUIPanel(CollectionsJournal);
local config = ezCollections.Config.Windows[self:GetParent():GetName()];
if not config.Layout and not config.Lock then
	WardrobeFrame:ClearAllPoints();
	WardrobeFrame:SetPoint("BOTTOMLEFT", UIParent, "BOTTOMLEFT", CollectionsJournal:GetLeft(), CollectionsJournal:GetBottom());
end
ShowUIPanel(WardrobeFrame);
WardrobeFrame.PortraitHelpBox:Hide();
CollectionsJournal.PortraitHelpBox:Hide();
ezCollections:SetCVarBitfield("closedInfoFrames", LE_FRAME_TUTORIAL_EZCOLLECTIONS_PORTRAIT_BUTTON, true);

Scripts.OnShow:
self:SetFrameStrata("DIALOG");
self.Text:SetText(ezCollections.L["Tutorial.TransmogTab"]);
self:SetHeight(self.Text:GetHeight() + 42);
if ezCollections:GetCVarBitfield("closedInfoFrames", LE_FRAME_TUTORIAL_EZCOLLECTIONS_TRANSMOG_TAB) then
	self:Hide();
end

Scripts.OnLoad:
CollectionsJournalTitleText:SetText(COLLECTIONS);
SetPortraitToTexture(CollectionsJournalPortrait, [[Interface\AddOns\ezCollections\Interface\Icons\MountJournalPortrait]]);
CollectionsJournalTab4:SetText(ezCollections.L["Library"]);
PanelTemplates_SetNumTabs(self, 6);

-- Moved to ezCollections's OnInitialize to have CVars loaded
-- PanelTemplates_SetTab(self, tonumber(ezCollections:GetCVar("petJournalTab")) or 5);

local onEnter = self:GetScript("OnEnter");
local onLeave = self:GetScript("OnLeave");
UIMenuButtonStretchMixin_OnLoad(self);
self:SetScript("OnEnter", onEnter);
self:SetScript("OnLeave", onLeave);

self:RegisterForClicks("LeftButtonUp", "RightButtonUp");

local scale = 1.5;
self.Icon:SetSize(self:GetWidth() - 10, self:GetHeight() - 10);
self.OuterGlow:SetSize(self:GetWidth() * scale, self:GetHeight() * scale);
self.Ants:SetSize(self:GetWidth() * scale * 0.85, self:GetHeight() * scale * 0.85);

self:GetHighlightTexture():ClearAllPoints();
self:GetHighlightTexture():SetPoint("CENTER");
self:GetHighlightTexture():SetSize(self:GetWidth() * 0.85, self:GetHeight() * 0.85);

function self:Attach(parent, frameLayerSource, tooltipHeader, tooltipText)
	if self:GetParent() ~= parent then
		self:SetParent(parent);
		self:ClearAllPoints();
		self:SetPoint("BOTTOMRIGHT", -9, 7);
		if not parent.__clickCollectHooked then
			parent.__clickCollectHooked = true;
			parent:HookScript("OnHide", function(parent)
				if self:GetParent() == parent then
					self:Set(false);
				end
			end);
		end
	end
	if frameLayerSource then
		self:SetFrameLevel(frameLayerSource:GetFrameLevel() + 1);
	end
	self.tooltipHeader = tooltipHeader;
	self.tooltipText = tooltipText;
	self:Show();
end
function self:Set(enable)
	if ezCollections.ClickCollect ~= nil and ezCollections.ClickCollect ~= enable then
		ezCollections.ClickCollect = enable;
		if enable then
			self.Ants:Show();
			self.Ants.FadeOut:Stop();
			self.Ants.FadeIn:Play();
			self.OuterGlow:Show();
			self.OuterGlow.FadeOut:Stop();
			self.OuterGlow.FadeIn:Play();
			if InRepairMode() then
				HideRepairCursor();
			end
			PlaySoundFile([[Sound\Interface\MagicClick.wav]]);
		else
			self.Ants.FadeIn:Stop();
			self.Ants.FadeOut:Play();
			self.OuterGlow.FadeIn:Stop();
			self.OuterGlow.FadeOut:Play();
			ResetCursor();
		end
	end
end

Scripts.OnClick:
if button ~= "LeftButton" then
	if ezCollections.ClickCollect then
		self:Set(false);
	end
	return;
end
if ezCollections.ClickCollect == nil then
	ezCollections.ClickCollect = false;
	hooksecurefunc("PickupContainerItem", function(bag, slot)
		if ezCollections.ClickCollect and CursorHasItem() then
			local type, itemID, link = GetCursorInfo();
			ClearCursor();
			if bag == -1 then
				bag = 39 + slot;
				slot = nil;
			end
			if ezCollections.itemUnderCursor.ID == itemID and ezCollections.itemUnderCursor.Bag == bag and ezCollections.itemUnderCursor.Slot == slot then
				PlaySoundFile([[Sound\Interface\MagicClick.wav]]);
				if slot then
					ezCollections:SendAddonMessage(format("UNLOCKSKIN:%d %d %d", itemID, bag, slot - 1));
				else
					ezCollections:SendAddonMessage(format("UNLOCKSKIN:%d %d", itemID, bag - 1));
				end
			end
		end
	end);
	local suppress = false;
	local function overrideCursor()
		if not suppress and ezCollections.ClickCollect then
			suppress = true;
			SetCursor(ezCollections.itemUnderCursor.ID and "CAST_CURSOR" or "CAST_ERROR_CURSOR");
			suppress = false;
		end
	end
	hooksecurefunc("SetCursor", overrideCursor);
	hooksecurefunc("ResetCursor", overrideCursor);
	hooksecurefunc("ShowInspectCursor", overrideCursor);
	hooksecurefunc("ShowMerchantSellCursor", overrideCursor);
	hooksecurefunc("ShowInventorySellCursor", overrideCursor);
	hooksecurefunc("ShowContainerSellCursor", overrideCursor);
	hooksecurefunc("ShowRepairCursor", function()
		if ezCollections.ClickCollect then
			self:Set(false);
		end
	end);
	hooksecurefunc("StaticPopup_EscapePressed", function() -- Hack to allow cancelling ClickCollect with Escape
		if ezCollections.ClickCollect then
			self:Set(false);
			GameMenuFrame:Show();
		end
	end);
	WorldFrame:HookScript("OnMouseDown", function()
		self:Set(false);
	end);
end

PlaySound("igMainMenuOptionCheckBoxOn");
self:Set(not ezCollections.ClickCollect);

Scripts.OnEnter:
GameTooltip:SetOwner(self, "ANCHOR_RIGHT");
GameTooltip:SetText(self.tooltipHeader);
GameTooltip:AddLine(self.tooltipText, HIGHLIGHT_FONT_COLOR.r, HIGHLIGHT_FONT_COLOR.g, HIGHLIGHT_FONT_COLOR.b, 1);
GameTooltip:Show();

Scripts.OnUpdate:
AnimateTexCoords(self.Ants, 256, 256, 48, 48, 22, elapsed, 0.01);
if ezCollections.ClickCollect then
	SetCursor(ezCollections.itemUnderCursor.ID and "CAST_CURSOR" or "CAST_ERROR_CURSOR");
end
